def match_brackets(brackets):
    # Initialize an empty stack
    stack = []

    # Iterate over each bracket in the input string
    for i, bracket in enumerate(brackets):
        # Check if the current bracket is an opening bracket
        if bracket == '[':
            # Push the opening bracket onto the stack along with its index
            stack.append((bracket, i))
        elif bracket == ']':
            # If the stack is empty, there's no matching opening bracket
            if not stack:
                return f"Unmatched closing bracket at index {i}"

            # Pop the top element from the stack (opening bracket and its index)
            opening_bracket, opening_index = stack.pop()

            # Check if the popped opening bracket matches the current closing bracket
            if opening_bracket != '(':
                return f"Mismatched brackets: opening '{opening_bracket}' at index {opening_index} does not match closing '{bracket}'"

    # If the stack is empty, all brackets have been matched
    if not stack:
        return "All brackets have been matched"
    else:
        # Return an error message for unmatched opening brackets in the stack
        return "Unmatched opening brackets: " + str(stack)

